const items = $input.all();

return items.map((item, index) => {
  let link = item.json.link || '';
  if (link && !link.startsWith('http')) link = 'https://www.htdi.by' + link;

  let image = item.json.image || '';
  if (image && !image.startsWith('http')) image = 'https://www.htdi.by' + image;

  let desc = (item.json.description || 'Новость с HTDI.by').trim();
  if (image) {
    desc = `<img src="${image}" style="max-width:100%;height:auto;border-radius:8px;" alt="${item.json.title || ''}"/><br><br>${desc}`;
  }

  return {
    json: {
      title: (item.json.title || `Новость ${index + 1}`).trim(),
      link: link,
      description: desc,
      pubDate: new Date().toUTCString(),
      guid: link || `htdi-${Date.now()}-${index}`
    }
  };
});

const items = $input.all();
let rss = `<?xml version="1.0" encoding="UTF-8"?>
<rss version="2.0">
<channel>
<title>HTDI.by — Новости IT Беларуси</title>
<link>https://www.htdi.by</link>
<description>Агрегатор технологий и цифровой инфраструктуры</description>
`;

items.forEach(item => {
  rss += `<item>
<title>${item.json.title}</title>
<link>${item.json.link}</link>
<description><![CDATA[${item.json.description}]]></description>
<pubDate>${item.json.pubDate}</pubDate>
<guid>${item.json.guid}</guid>
</item>
`;
});

rss += '</channel></rss>';

return [{ json: { rss } }];
